// // This module implements a 4-bit synchronous binary down counter with a negative edge triggered clock, an active low synchronous reset, and a decrement value input. The counter should decrement the current value when a decrement signal is high.
module binary_up_counter_4bit (
    input clk,
    input reset,
    input load,
    input [3:0] preset_value,
    output reg [3:0] q);

always @(posedge clk) begin
    if (reset)
        q <= 4'b0000;
    else if (load)
        q <= preset_value;
    else
        q <= q + 1;
    end

endmodule
